select @tu_ngay as date_from, @den_ngay as date_to
exec rs_rptIncomeStatementbyJob @tu_ngay, @den_ngay, @ma_vv_me, @ma_vv, @kieu_xem, @kieu_nhom, @ma_dvcs, @mau_bc, @@language, @@userID, @@admin







