      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  onchange$ReportViewType(f.getItem('kieu_xem'), true);
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      var x = f.getItemValue('mau_bc'), d1 = f.getItem('tu_ngay').value, d2 = f.getItem('den_ngay').value;
      g._ValueFormType = x;
      g._alterTitle = [null, [['%d1', d1, true], ['%d2', d2, true]]];
      g._queryFilterString = getQueryFilterString(f, 'tu_ngay, den_ngay, ma_dvcs, ma_vv_me, mau_bc');

      if (!g._v) g._v = x;
      if (g._v != x) {
        remove$GridReport$Filter(g);
        g._v = x;
      }
      break;
    default:
      break;
  }
}
function onchange$ReportViewType(o, force) {
  var f = o.parentForm, k = f.getItem('kieu_xem').value;
  setItemDisable(f, 'kieu_nhom', k == '1');
  if (!force) {
    f.setItemValue('kieu_nhom', 1);
    if (k == 1) f.getItem('ma_dvcs').focus();
    else f.getItem('kieu_nhom').focus();
  }
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
/* </flatten> */



